import { getMeta, setMeta, META } from '../metadata';
import type { ParamDefinition, ParamType } from '../types';

// ─── Factory ───────────────────────────────────────────────────────────────

function createParamDecorator(type: ParamType, key?: string): ParameterDecorator {
  return (target, propertyKey, parameterIndex) => {
    if (typeof propertyKey !== 'string') return;

    const params: ParamDefinition[] =
      getMeta(META.PARAMS, target.constructor) ?? [];

    params.push({ methodName: propertyKey, index: parameterIndex, type, key });
    setMeta(META.PARAMS, params, target.constructor);
  };
}

// ─── Parameter Decorators ──────────────────────────────────────────────────

/**
 * Injects the full request body, or a specific key from it.
 *
 * @example
 * ```ts
 * create(@Body() dto: CreateUserDto) { ... }
 * create(@Body('name') name: string) { ... }
 * ```
 */
export const Body    = (key?: string) => createParamDecorator('body',    key);

/**
 * Injects query-string params, or a specific key.
 *
 * @example
 * ```ts
 * search(@Query('q') q: string) { ... }
 * ```
 */
export const Query   = (key?: string) => createParamDecorator('query',   key);

/**
 * Injects URL route params, or a specific key.
 *
 * @example
 * ```ts
 * findOne(@Params('id') id: string) { ... }
 * ```
 */
export const Params  = (key?: string) => createParamDecorator('params',  key);

/**
 * Injects request headers, or a specific header value.
 *
 * @example
 * ```ts
 * auth(@Headers('authorization') token: string) { ... }
 * ```
 */
export const Headers = (key?: string) => createParamDecorator('headers', key);

/**
 * Injects cookies, or a specific cookie value.
 *
 * @example
 * ```ts
 * session(@Cookie('session_id') sessionId: string) { ... }
 * ```
 */
export const Cookie  = (key?: string) => createParamDecorator('cookie',  key);

/**
 * Injects the raw `Request` object.
 */
export const Req     = () => createParamDecorator('request');

/**
 * Injects Elysia's `set` object (for setting status, headers on the response).
 */
export const Res     = () => createParamDecorator('set');

/**
 * Injects the full Elysia context object (escape hatch).
 */
export const Ctx     = () => createParamDecorator('context');
