import { getMeta, META } from '../metadata';
import { DIContainer } from './container';
import type { Constructor, ModuleOptions, Provider } from '../types';

export class ModuleLoader {
  /** Prevents double-loading the same module */
  private readonly loaded = new Set<Constructor>();
  /** Ordered list of all resolved controller classes */
  private readonly allControllers: Constructor[] = [];

  constructor(private readonly container: DIContainer) {}

  // ── Public ──────────────────────────────────────────────────────────────

  load(moduleClass: Constructor): void {
    if (this.loaded.has(moduleClass)) return;
    this.loaded.add(moduleClass);

    const options: ModuleOptions = getMeta(META.MODULE, moduleClass) ?? {};

    // 1. Load imported modules first (depth-first)
    for (const imported of options.imports ?? []) {
      this.load(imported);
    }

    // 2. Register providers
    for (const provider of options.providers ?? []) {
      this.container.register(provider as Provider);
    }

    // 3. Register controllers (also need to be in the container for DI)
    for (const controller of options.controllers ?? []) {
      this.container.register(controller);
      this.allControllers.push(controller);
    }
  }

  getControllers(): Constructor[] {
    return this.allControllers;
  }
}
