import type { ZodType } from 'zod';
import { getMeta, setMeta, META } from '../metadata';
import type { ValidationDefinition, ValidationTarget } from '../types';

// ─── Factory ───────────────────────────────────────────────────────────────

function createValidationDecorator(target: ValidationTarget, schema: ZodType<any>): MethodDecorator {
  return (proto: object, propertyKey: string | symbol) => {
    if (typeof propertyKey !== 'string') return;

    const existing: ValidationDefinition[] =
      getMeta(META.VALIDATION, proto.constructor) ?? [];

    const entry = existing.find(e => e.methodName === propertyKey);
    if (entry) {
      entry.rules.push({ target, schema });
    } else {
      existing.push({ methodName: propertyKey, rules: [{ target, schema }] });
    }

    setMeta(META.VALIDATION, existing, proto.constructor);
  };
}

// ─── Public Decorators ─────────────────────────────────────────────────────

/**
 * Validates `request.body` against a Zod schema before the handler runs.
 * Returns `422 Unprocessable Entity` with structured error details on failure.
 *
 * @example
 * ```ts
 * const CreateUserDto = z.object({ name: z.string(), email: z.string().email() });
 *
 * @Post('/')
 * @ValidateBody(CreateUserDto)
 * create(@Body() body: z.infer<typeof CreateUserDto>) { ... }
 * ```
 */
export const ValidateBody   = (schema: ZodType<any>) => createValidationDecorator('body',   schema);

/**
 * Validates query-string params against a Zod schema.
 *
 * @example
 * ```ts
 * @Get('/')
 * @ValidateQuery(z.object({ page: z.coerce.number().min(1) }))
 * list(@Query() q: { page: number }) { ... }
 * ```
 */
export const ValidateQuery  = (schema: ZodType<any>) => createValidationDecorator('query',  schema);

/**
 * Validates URL route params against a Zod schema.
 *
 * @example
 * ```ts
 * @Get('/:id')
 * @ValidateParams(z.object({ id: z.coerce.number() }))
 * findOne(@Params('id') id: number) { ... }
 * ```
 */
export const ValidateParams = (schema: ZodType<any>) => createValidationDecorator('params', schema);
