import { getMeta, META } from '../metadata';
import { HttpException } from './exceptions';
import { DIContainer } from './container';
import type {
  Constructor,
  ExceptionFilter,
  ExceptionFilterDefinition,
  UseFilterDefinition,
} from '../types';

// ─── FilterRunner ──────────────────────────────────────────────────────────

export class FilterRunner {
  constructor(
    private readonly container: DIContainer,
    private readonly globalFilters: Constructor<ExceptionFilter>[] = []
  ) {}

  /**
   * Attempt to handle `error` using:
   *   1. Method-level filters (most specific)
   *   2. Controller-level filters
   *   3. Global filters
   *   4. Default HttpException handler
   *   5. Fallback 500
   */
  async run(
    error: unknown,
    ctx: Record<string, any>,
    ControllerClass: Constructor,
    methodName: string
  ): Promise<unknown> {
    const defs: UseFilterDefinition[] = getMeta(META.FILTER, ControllerClass) ?? [];

    // Collect method-level then controller-level then global
    const methodFilters  = defs.filter(d => d.methodName === methodName).flatMap(d => d.filters);
    const controllerFilters = defs.filter(d => d.methodName === '*').flatMap(d => d.filters);
    const allFilters = [...methodFilters, ...controllerFilters, ...this.globalFilters];

    for (const FilterClass of allFilters) {
      const catchDef: ExceptionFilterDefinition | undefined = getMeta(META.CATCH, FilterClass);

      // If @Catch() specified types, check if error matches
      if (catchDef && catchDef.exceptions.length > 0) {
        const matches = catchDef.exceptions.some(E => error instanceof E);
        if (!matches) continue;
      }

      // Run this filter
      const filter = this.container.resolve<ExceptionFilter>(FilterClass);
      return filter.catch(error, ctx);
    }

    // ── Default handling ─────────────────────────────────────────────────

    if (error instanceof HttpException) {
      ctx.set.status = error.statusCode;
      return error.toJSON();
    }

    // Unknown error → 500
    console.error('[elysia-modules] Unhandled exception:', error);
    ctx.set.status = 500;
    return {
      statusCode: 500,
      error: 'Internal Server Error',
      message: error instanceof Error ? error.message : 'An unexpected error occurred',
    };
  }
}
