import 'reflect-metadata';

// ─── Metadata Keys ─────────────────────────────────────────────────────────

export const META = {
  MODULE:      'elysia_mod:module',
  CONTROLLER:  'elysia_mod:controller',
  INJECTABLE:  'elysia_mod:injectable',
  ROUTES:      'elysia_mod:routes',
  PARAMS:      'elysia_mod:params',
  INJECT:      'elysia_mod:inject',
  MIDDLEWARE:  'elysia_mod:middleware',
  VALIDATION:  'elysia_mod:validation',
  FILTER:      'elysia_mod:filter',
  CATCH:       'elysia_mod:catch',
} as const;

// ─── Metadata Helpers ──────────────────────────────────────────────────────

export function setMeta(key: string, value: unknown, target: object): void {
  Reflect.defineMetadata(key, value, target);
}

export function getMeta<T>(key: string, target: object): T | undefined {
  return Reflect.getMetadata(key, target) as T | undefined;
}

/** Returns the TypeScript-emitted constructor param types (requires emitDecoratorMetadata) */
export function getParamTypes(target: object): any[] {
  return (Reflect.getMetadata('design:paramtypes', target) as any[]) ?? [];
}
