import type { Elysia } from 'elysia';
import { getMeta, META } from '../metadata';
import { DIContainer } from './container';
import { ModuleLoader } from './loader';
import { LifecycleRunner } from './lifecycle';
import { FilterRunner } from './filters';
import { runValidation } from './validation';
import type {
  Constructor,
  RouteDefinition,
  ParamDefinition,
  MiddlewareDefinition,
  ValidationDefinition,
  ElysiaMiddleware,
  ExceptionFilter,
} from '../types';

// ─── Factory options ───────────────────────────────────────────────────────

export interface ElysiaModuleOptions {
  /** Global exception filters — applied after controller/route filters */
  globalFilters?: Constructor<ExceptionFilter>[];
  /** Register shutdown hooks (SIGINT / SIGTERM) automatically */
  enableShutdownHooks?: boolean;
}

// ─── Arg resolver ─────────────────────────────────────────────────────────

function resolveHandlerArgs(
  ctx: Record<string, any>,
  methodName: string,
  allParams: ParamDefinition[]
): unknown[] {
  const methodParams = allParams.filter(p => p.methodName === methodName);
  if (methodParams.length === 0) return [ctx];

  const args: unknown[] = [];
  for (const param of methodParams) {
    let value: unknown;
    switch (param.type) {
      case 'body':    value = param.key ? (ctx['body'] as any)?.[param.key]    : ctx['body'];    break;
      case 'query':   value = param.key ? (ctx['query'] as any)?.[param.key]   : ctx['query'];   break;
      case 'params':  value = param.key ? (ctx['params'] as any)?.[param.key]  : ctx['params'];  break;
      case 'headers': value = param.key ? (ctx['headers'] as any)?.[param.key] : ctx['headers']; break;
      case 'cookie':  value = param.key ? (ctx['cookie'] as any)?.[param.key]  : ctx['cookie'];  break;
      case 'request': value = ctx['request']; break;
      case 'set':     value = ctx['set'];     break;
      case 'store':   value = ctx['store'];   break;
      case 'context':
      default:        value = ctx;
    }
    args[param.index] = value;
  }
  return args;
}

// ─── Path normaliser ──────────────────────────────────────────────────────

function joinPaths(prefix: string, path: string): string {
  const joined = `${prefix}${path}`.replace(/\/+/g, '/');
  return joined !== '/' ? joined.replace(/\/$/, '') : joined;
}

// ─── Middleware runner ─────────────────────────────────────────────────────

async function runMiddlewares(
  middlewares: Constructor<ElysiaMiddleware>[],
  ctx: Record<string, any>,
  container: DIContainer
): Promise<boolean> {
  for (const MwClass of middlewares) {
    let nextCalled = false;
    const instance = container.resolve<ElysiaMiddleware>(MwClass);
    await instance.use(ctx, async () => { nextCalled = true; });
    if (!nextCalled) return false;
  }
  return true;
}

// ─── Public factory ───────────────────────────────────────────────────────

export function createElysiaModule(
  RootModule: Constructor,
  options: ElysiaModuleOptions = {}
) {
  return async (app: Elysia) => {
    const container    = new DIContainer();
    const lifecycle    = new LifecycleRunner();
    const modLoader    = new ModuleLoader(container);

    for (const f of options.globalFilters ?? []) container.register(f);

    modLoader.load(RootModule);

    const filterRunner = new FilterRunner(container, options.globalFilters ?? []);

    for (const ControllerClass of modLoader.getControllers()) {
      const prefix      = getMeta<string>(META.CONTROLLER, ControllerClass) ?? '';
      const routes      = getMeta<RouteDefinition[]>(META.ROUTES, ControllerClass) ?? [];
      const params      = getMeta<ParamDefinition[]>(META.PARAMS, ControllerClass) ?? [];
      const mwDefs      = getMeta<MiddlewareDefinition[]>(META.MIDDLEWARE, ControllerClass) ?? [];
      const validations = getMeta<ValidationDefinition[]>(META.VALIDATION, ControllerClass) ?? [];

      const instance = container.resolve<any>(ControllerClass);
      lifecycle.register(instance);

      const controllerMws = mwDefs.filter(d => d.methodName === '*').flatMap(d => d.middlewares);

      for (const route of routes) {
        const fullPath  = joinPaths(prefix, route.path);
        const method    = route.method.toLowerCase() as 'get'|'post'|'put'|'delete'|'patch'|'head'|'options';
        const routeMws  = mwDefs.filter(d => d.methodName === route.propertyKey).flatMap(d => d.middlewares);
        const allMws    = [...controllerMws, ...routeMws];

        (app as any)[method](fullPath, async (ctx: Record<string, unknown>) => {
          try {
            const ctxMut = ctx as Record<string, any>;

            if (allMws.length > 0) {
              const passed = await runMiddlewares(allMws, ctxMut, container);
              if (!passed) return;
            }

            const validationError = await runValidation(ctxMut, route.propertyKey, validations);
            if (validationError) {
              ctxMut.set.status = 422;
              return {
                statusCode: 422,
                error: 'Unprocessable Entity',
                message: 'Validation failed',
                errors: validationError.errors,
              };
            }

            const args = resolveHandlerArgs(ctxMut, route.propertyKey, params);
            return await (instance[route.propertyKey] as (...a: unknown[]) => unknown)(...args);

          } catch (err) {
            return filterRunner.run(err, ctx as Record<string, any>, ControllerClass, route.propertyKey);
          }
        });
      }
    }

    await lifecycle.runModuleInit();
    await lifecycle.runApplicationBootstrap();

    if (options.enableShutdownHooks) lifecycle.enableShutdownHooks();

    return app;
  };
}
