import { setMeta, META } from '../metadata';

/**
 * Marks a class as an HTTP controller with an optional route prefix.
 *
 * @example
 * ```ts
 * @Controller('/users')
 * export class UserController {}
 * ```
 */
export function Controller(prefix = ''): ClassDecorator {
  return (target) => {
    // Normalise: ensure leading slash, strip trailing slash
    const clean = prefix.startsWith('/') ? prefix : `/${prefix}`;
    const normalised = clean === '/' ? '' : clean.replace(/\/$/, '');
    setMeta(META.CONTROLLER, normalised, target);
  };
}
