import { getMeta, setMeta, META } from '../metadata';
import type { HttpMethod, RouteDefinition } from '../types';

// ─── Factory ───────────────────────────────────────────────────────────────

function createMethodDecorator(httpMethod: HttpMethod, path = ''): MethodDecorator {
  return (target, propertyKey) => {
    if (typeof propertyKey !== 'string') return;

    // Normalise path
    const normalised = path === ''
      ? '/'
      : path.startsWith('/') ? path : `/${path}`;

    const routes: RouteDefinition[] =
      getMeta(META.ROUTES, target.constructor) ?? [];

    routes.push({ method: httpMethod, path: normalised, propertyKey });
    setMeta(META.ROUTES, routes, target.constructor);
  };
}

// ─── HTTP Method Decorators ────────────────────────────────────────────────

/**
 * @example
 * ```ts
 * @Get('/') findAll() { ... }
 * @Get('/:id') findOne(@Params('id') id: string) { ... }
 * ```
 */
export const Get     = (path = '')  => createMethodDecorator('GET',     path);
export const Post    = (path = '')  => createMethodDecorator('POST',    path);
export const Put     = (path = '')  => createMethodDecorator('PUT',     path);
export const Delete  = (path = '')  => createMethodDecorator('DELETE',  path);
export const Patch   = (path = '')  => createMethodDecorator('PATCH',   path);
export const Head    = (path = '')  => createMethodDecorator('HEAD',    path);
export const Options = (path = '')  => createMethodDecorator('OPTIONS', path);
