import { getParamTypes, getMeta, META } from '../metadata';
import type {
  Constructor,
  Token,
  Provider,
  UseClassProvider,
  UseValueProvider,
  UseFactoryProvider,
} from '../types';

// ─── Type guards ───────────────────────────────────────────────────────────

function isUseClass<T>(p: Provider<T>): p is UseClassProvider<T> {
  return typeof p === 'object' && 'useClass' in p;
}

function isUseValue<T>(p: Provider<T>): p is UseValueProvider<T> {
  return typeof p === 'object' && 'useValue' in p;
}

function isUseFactory<T>(p: Provider<T>): p is UseFactoryProvider<T> {
  return typeof p === 'object' && 'useFactory' in p;
}

// ─── DIContainer ───────────────────────────────────────────────────────────

export class DIContainer {
  /** Resolved singleton instances */
  private readonly instances = new Map<Token, unknown>();
  /** Registered provider descriptors */
  private readonly registry  = new Map<Token, Provider>();

  // ── Registration ──────────────────────────────────────────────────────

  register(provider: Provider): void {
    if (typeof provider === 'function') {
      this.registry.set(provider, provider);
    } else if (isUseValue(provider)) {
      // Cache immediately — no instantiation needed
      this.instances.set(provider.provide, provider.useValue);
    } else {
      this.registry.set(provider.provide, provider);
    }
  }

  // ── Resolution ────────────────────────────────────────────────────────

  resolve<T>(token: Token<T>): T {
    if (this.instances.has(token)) {
      return this.instances.get(token) as T;
    }

    const provider = this.registry.get(token);
    if (!provider) {
      // Auto-register constructor providers that weren't explicitly declared
      if (typeof token === 'function') {
        this.register(token as Constructor);
        return this.resolve(token);
      }
      throw new ElysiaModulesError(
        `No provider found for token: ${String((token as any)?.name ?? token)}. ` +
        `Make sure it is listed in a module's providers array.`
      );
    }

    let instance: T;

    if (typeof provider === 'function') {
      instance = this.instantiate(provider as Constructor<T>);
    } else if (isUseClass(provider)) {
      instance = this.instantiate(provider.useClass);
    } else if (isUseFactory(provider)) {
      const deps = (provider.inject ?? []).map(dep => this.resolve(dep));
      instance = provider.useFactory(...deps) as T;
    } else {
      throw new ElysiaModulesError(`Malformed provider for token: ${String(token)}`);
    }

    this.instances.set(token, instance);
    return instance;
  }

  // ── Instantiation (constructor injection) ─────────────────────────────

  private instantiate<T>(ctor: Constructor<T>): T {
    const paramTypes: (Constructor | undefined)[] = getParamTypes(ctor);

    // Check for @Inject() token overrides
    const injectOverrides: Map<number, Token> =
      getMeta(META.INJECT, ctor) ?? new Map();

    const deps = paramTypes.map((type, i) => {
      const token = injectOverrides.get(i) ?? type;
      if (!token) {
        throw new ElysiaModulesError(
          `Cannot resolve dependency at index ${i} of ${ctor.name}. ` +
          `Either enable emitDecoratorMetadata or use @Inject(TOKEN).`
        );
      }
      return this.resolve(token);
    });

    return new ctor(...deps);
  }
}

// ─── Custom Error ─────────────────────────────────────────────────────────

export class ElysiaModulesError extends Error {
  constructor(message: string) {
    super(`[elysia-modules] ${message}`);
    this.name = 'ElysiaModulesError';
  }
}
