import { getMeta, setMeta, META } from '../metadata';
import type {
  Constructor,
  ExceptionFilter,
  ExceptionFilterDefinition,
  UseFilterDefinition,
} from '../types';

/**
 * Marks a class as an exception filter.
 * Pass the error type(s) this filter handles; omit to catch everything.
 *
 * @example
 * ```ts
 * // Catch a specific error type
 * @Catch(NotFoundException)
 * export class NotFoundFilter implements ExceptionFilter<NotFoundException> {
 *   catch(exception: NotFoundException, ctx: any) {
 *     ctx.set.status = 404;
 *     return { error: exception.message };
 *   }
 * }
 *
 * // Catch-all global filter
 * @Catch()
 * export class GlobalErrorFilter implements ExceptionFilter {
 *   catch(exception: unknown, ctx: any) {
 *     console.error(exception);
 *     ctx.set.status = 500;
 *     return { error: 'Internal server error' };
 *   }
 * }
 * ```
 */
export function Catch(...exceptions: Constructor<any>[]): ClassDecorator {
  return (target) => {
    const def: ExceptionFilterDefinition = {
      exceptions,
      filter: target as unknown as Constructor<ExceptionFilter>,
    };
    setMeta(META.CATCH, def, target);
  };
}

/**
 * Binds exception filter(s) to a controller (all routes) or a single route method.
 *
 * Filters are evaluated in order; the first matching filter wins.
 * Method-level filters take priority over controller-level filters.
 *
 * @example
 * ```ts
 * // Controller-wide
 * @UseFilter(NotFoundFilter, GlobalErrorFilter)
 * @Controller('/users')
 * export class UserController { ... }
 *
 * // Single route
 * @Post('/')
 * @UseFilter(ValidationExceptionFilter)
 * create(@Body() body: CreateUserDto) { ... }
 * ```
 */
export function UseFilter(
  ...filters: Constructor<ExceptionFilter>[]
): ClassDecorator & MethodDecorator {
  return (target: any, propertyKey?: string | symbol) => {
    const isMethod = propertyKey !== undefined;
    const methodName = isMethod ? String(propertyKey) : '*';
    const storageTarget = isMethod ? target.constructor : target;

    const existing: UseFilterDefinition[] =
      getMeta(META.FILTER, storageTarget) ?? [];

    existing.push({ methodName, filters });
    setMeta(META.FILTER, existing, storageTarget);
  };
}
