import type { ZodError } from 'zod';
import type { ValidationDefinition, ValidationError } from '../types';

// ─── ValidationRunner ─────────────────────────────────────────────────────

/**
 * Runs all registered Zod validations for a route handler.
 * Returns a structured 422 response if any schema fails,
 * or `null` if everything passes.
 */
export async function runValidation(
  ctx: Record<string, any>,
  methodName: string,
  allValidations: ValidationDefinition[]
): Promise<{ status: 422; errors: ValidationError[] } | null> {
  const defs = allValidations.find(v => v.methodName === methodName);
  if (!defs) return null;

  const errors: ValidationError[] = [];

  for (const rule of defs.rules) {
    const raw = ctx[rule.target];

    const result = await rule.schema.safeParseAsync(raw);
    if (!result.success) {
      errors.push({
        target: rule.target,
        issues: (result.error as ZodError).issues,
      });
    } else {
      // Replace the ctx value with the parsed (and coerced) value
      ctx[rule.target] = result.data;
    }
  }

  return errors.length > 0 ? { status: 422, errors } : null;
}
