import type {
  OnModuleInit,
  OnModuleDestroy,
  OnApplicationBootstrap,
  OnApplicationShutdown,
} from '../types';

// ─── Hook checks (interface detection via duck-typing) ─────────────────────

function hasHook<K extends string>(inst: unknown, hook: K): inst is Record<K, (...args: any[]) => unknown> {
  return typeof (inst as any)?.[hook] === 'function';
}

// ─── LifecycleRunner ───────────────────────────────────────────────────────

/**
 * Runs lifecycle hooks across all registered instances in the correct order.
 *
 * Order:
 *   1. onModuleInit       — providers & controllers, depth-first module order
 *   2. onApplicationBootstrap — after all modules loaded, before listen()
 *   3. onModuleDestroy / onApplicationShutdown — on process signal
 */
export class LifecycleRunner {
  private instances: unknown[] = [];

  /** Register an instance that may implement lifecycle interfaces */
  register(instance: unknown): void {
    this.instances.push(instance);
  }

  // ── Init phase ────────────────────────────────────────────────────────

  async runModuleInit(): Promise<void> {
    for (const inst of this.instances) {
      if (hasHook(inst, 'onModuleInit')) {
        await inst.onModuleInit();
      }
    }
  }

  async runApplicationBootstrap(): Promise<void> {
    for (const inst of this.instances) {
      if (hasHook(inst, 'onApplicationBootstrap')) {
        await inst.onApplicationBootstrap();
      }
    }
  }

  // ── Shutdown phase ────────────────────────────────────────────────────

  async runModuleDestroy(): Promise<void> {
    // Reverse order — last-registered destroyed first
    for (const inst of [...this.instances].reverse()) {
      if (hasHook(inst, 'onModuleDestroy')) {
        await inst.onModuleDestroy();
      }
    }
  }

  async runApplicationShutdown(signal?: string): Promise<void> {
    for (const inst of [...this.instances].reverse()) {
      if (hasHook(inst, 'onApplicationShutdown')) {
        await inst.onApplicationShutdown(signal);
      }
    }
  }

  /**
   * Registers SIGINT / SIGTERM listeners so shutdown hooks fire automatically.
   * Call this after the app starts listening.
   */
  enableShutdownHooks(): void {
    const shutdown = async (signal: string) => {
      console.log(`\n[elysia-modules] Received ${signal}, shutting down…`);
      await this.runApplicationShutdown(signal);
      await this.runModuleDestroy();
      process.exit(0);
    };

    process.once('SIGINT',  () => shutdown('SIGINT'));
    process.once('SIGTERM', () => shutdown('SIGTERM'));
  }
}
